SELECT tt.*, ktc.id AS store_tags_id, c.brand_ids, c.brand_name FROM kol_tags tt LEFT JOIN kol_tag_category ktc ON tt.store_tags = ktc.category_name LEFT JOIN kol_tag_product ktp ON tt.id = ktp.tag_id LEFT JOIN (SELECT tag_id, a.platform_type, GROUP_CONCAT( b.id ) AS brand_ids, GROUP_CONCAT( b.brand_name ) AS brand_name FROM kol_tag_brand a LEFT JOIN kol_brand b ON a.brand_id = b.id GROUP BY tag_id,platform_type) c ON tt.id = c.tag_id and tt.platform_type = c.platform_type WHERE tt.is_delete = 0 AND tt.is_active = 1
AND tt.tag_name like CONCAT('%', #{tiktokTagsModel.tagName}, '%')
AND tt.sub_category like CONCAT('%', #{tiktokTagsModel.subCategory}, '%')
AND tt.tag_product like CONCAT('%', #{tiktokTagsModel.tagProduct}, '%')
AND tt.tag_audience like CONCAT('%', #{tiktokTagsModel.tagAudience}, '%')
AND tt.platform_type = #{tiktokTagsModel.platformType}
AND tt.tag_type = #{tiktokTagsModel.tagType}
AND JSON_SEARCH(tt.store_tags, 'one', #{element}, NULL, '$[*]') IS NOT NULL AND JSON_EXTRACT(tt.store_tags, '$[*]') LIKE CONCAT('%', #{element}, '%')
AND tt.category_id IN
#{item}
AND tt.tag_product LIKE CONCAT('%', #{tiktokTagsModel.tagProduct}, '%')
AND ktp.brand_id = #{tiktokTagsModel.brandId}
GROUP BY tt.id
ORDER BY ${tiktokTagsModel.column} ${tiktokTagsModel.order}
ORDER BY sort_code IS NULL ASC, sort_code asc

