AND tt.tag_name like CONCAT('%', #{tiktokTagsModel.tagName}, '%')

SELECT tt.*, ktc.id AS store_tags_id, c.brand_ids, c.brand_name FROM kol_tags tt LEFT JOIN kol_tag_product ktp ON tt.id = ktp.tag_id LEFT JOIN kol_tag_category ktc ON tt.store_tags = ktc.category_name LEFT JOIN ( SELECT tag_id, platform_type, GROUP_CONCAT( b.id ) AS brand_ids, GROUP_CONCAT( b.brand_name ) AS brand_name FROM kol_tag_brand a LEFT JOIN kol_brand b ON a.brand_id = b.id WHERE a.platform_type = #{tiktokTagsModel.platformType} GROUP BY tag_id, platform_type ) c ON tt.id = c.tag_id AND tt.platform_type = c.platform_type WHERE tt.is_delete = 0 AND tt.is_active = 1
AND ktp.is_delete = 0 AND ktp.product_id = #{tiktokTagsModel.productId}
