AND tt.tag_name like CONCAT('%', #{tiktokTagsModel.tagName}, '%')
AND tt.sub_category like CONCAT('%', #{tiktokTagsModel.subCategory}, '%')
AND tt.tag_product like CONCAT('%', #{tiktokTagsModel.tagProduct}, '%')
AND tt.tag_audience like CONCAT('%', #{tiktokTagsModel.tagAudience}, '%')
AND tt.platform_type = #{tiktokTagsModel.platformType}
AND tt.tag_type = #{tiktokTagsModel.tagType}
AND JSON_SEARCH(tt.store_tags, 'one', #{element}, NULL, '$[*]') IS NOT NULL AND JSON_EXTRACT(tt.store_tags, '$[*]') LIKE CONCAT('%', #{element}, '%')
AND tt.category_id IN
#{item}
AND tt.tag_product LIKE CONCAT('%', #{tiktokTagsModel.tagProduct}, '%')
AND ktp.brand_id = #{tiktokTagsModel.brandId}
group by tt.id ) AS tag_count

SELECT DISTINCT kt.tag_name, CAST( countries.unassignedCount AS UNSIGNED ) AS tagNum, kt.snapshot_time FROM `kol_tags` kt, JSON_TABLE ( kt.country_data_json, '$[*]' COLUMNS ( country VARCHAR ( 255 ) PATH '$.country', unassignedCount INT PATH '$.unassignedCount' ) ) AS countries
platform_type = #{searchModel.platformType}
AND countries.country = #{searchModel.countryCode}
ORDER BY tagNum DESC

